/**
 * Calculates the Return on Investment (ROI), Payback Period, and Total Net Savings
 * for a home renewable energy system.
 *
 * @param {object} inputs - The input parameters for the calculation.
 * @param {number} inputs.initialCost - Total system installation cost in dollars.
 * @param {number} inputs.systemSizeKw - System size in kWdc.
 * @param {number} inputs.annualProductionKwhKw - Estimated annual production per kW (kWh/kWdc).
 * @param {number} inputs.currentElectricityCostCents - Current electricity cost in cents/kWh.
 * @param {number} inputs.electricityInflationRatePercent - Annual electricity price inflation rate as a percentage.
 * @param {number} inputs.annualDegradationRatePercent - Annual system degradation rate as a percentage.
 * @param {number} inputs.federalTaxCreditPercent - Federal tax credit as a percentage of initial cost.
 * @param {number} inputs.stateLocalRebateDollars - State/local upfront rebate in dollars.
 * @param {number} inputs.annualMaintenanceCostDollars - Annual maintenance cost in dollars.
 * @param {number} inputs.projectLifeYears - Project life in years.
 * @returns {object} An object containing paybackPeriodYears, totalNetSavingsDollars, and roiPercent.
 */
function calculateRenewableEnergyROI(inputs) {
  const {
    initialCost,
    systemSizeKw,
    annualProductionKwhKw,
    currentElectricityCostCents,
    electricityInflationRatePercent,
    annualDegradationRatePercent,
    federalTaxCreditPercent,
    stateLocalRebateDollars,
    annualMaintenanceCostDollars,
    projectLifeYears,
  } = inputs;

  // Input validation and conversion
  if (initialCost <= 0 || systemSizeKw <= 0 || annualProductionKwhKw <= 0 || projectLifeYears <= 0) {
    return {
      paybackPeriodYears: NaN,
      totalNetSavingsDollars: NaN,
      roiPercent: NaN,
      error: "Initial cost, system size, annual production, and project life must be positive values."
    };
  }

  const currentElectricityCostDollars = currentElectricityCostCents / 100;
  const electricityInflationFactor = 1 + (electricityInflationRatePercent / 100);
  const degradationFactor = 1 - (annualDegradationRatePercent / 100);

  // Calculate Net Initial Investment
  const federalTaxCreditAmount = initialCost * (federalTaxCreditPercent / 100);
  const netInitialCost = initialCost - federalTaxCreditAmount - stateLocalRebateDollars;

  if (netInitialCost <= 0) {
      return {
          paybackPeriodYears: 0,
          totalNetSavingsDollars: (annualProductionKwhKw * systemSizeKw * currentElectricityCostDollars * projectLifeYears) - (annualMaintenanceCostDollars * projectLifeYears) > 0 ? (annualProductionKwhKw * systemSizeKw * currentElectricityCostDollars * projectLifeYears) - (annualMaintenanceCostDollars * projectLifeYears) : 0,
          roiPercent: Infinity,
          // Edge case: if net initial cost is 0 or negative due to high incentives,
          // payback is immediate, ROI is theoretically infinite (or extremely high).
          // We'll set total savings to be just the accumulated savings over project life.
          // Note: a true financial model might cap ROI or use specific metrics here.
      };
  }

  let accumulatedNetCashFlow = -netInitialCost;
  let paybackPeriodYears = Infinity;
  let currentAnnualProduction = systemSizeKw * annualProductionKwhKw;
  let currentElectricityPrice = currentElectricityCostDollars;
  let totalEnergySavingsOverLife = 0;
  let totalMaintenanceCostsOverLife = 0;

  for (let year = 1; year <= projectLifeYears; year++) {
    // Energy generated for the current year, accounting for degradation
    const annualGeneratedEnergy = currentAnnualProduction;

    // Energy savings for the current year, accounting for electricity price inflation
    const annualEnergySavings = annualGeneratedEnergy * currentElectricityPrice;

    // Net annual cash flow
    const annualNetCashFlow = annualEnergySavings - annualMaintenanceCostDollars;

    accumulatedNetCashFlow += annualNetCashFlow;
    totalEnergySavingsOverLife += annualEnergySavings;
    totalMaintenanceCostsOverLife += annualMaintenanceCostDollars;

    // Check for payback period
    if (paybackPeriodYears === Infinity && accumulatedNetCashFlow >= 0) {
      paybackPeriodYears = year;
      // Linear interpolation for more precise payback period if accumulatedNetCashFlow > 0
      if (year > 1) {
          const prevYearAccumulated = accumulatedNetCashFlow - annualNetCashFlow;
          paybackPeriodYears = year - (accumulatedNetCashFlow / annualNetCashFlow);
      } else {
          // If payback in first year, just use the fractional part if needed
          paybackPeriodYears = netInitialCost / annualNetCashFlow;
      }
    }

    // Update values for next year
    currentAnnualProduction *= degradationFactor;
    currentElectricityPrice *= electricityInflationFactor;
  }

  const totalNetSavingsDollars = accumulatedNetCashFlow + netInitialCost; // Re-add initial investment for total *savings*

  // Calculate ROI
  const roiPercent = (totalNetSavingsDollars / netInitialCost) * 100;

  return {
    paybackPeriodYears: isFinite(paybackPeriodYears) ? Math.max(0, paybackPeriodYears) : -1, // Use -1 or a specific indicator for no payback
    totalNetSavingsDollars: totalNetSavingsDollars,
    roiPercent: isFinite(roiPercent) ? roiPercent : Infinity
  };
}
